package com.evolua.emotional.interfaces.rest; import com.evolua.emotional.application.CheckInService; import com.evolua.emotional.infrastructure.security.CurrentUserProvider; import io.swagger.v3.oas.annotations.Operation; import jakarta.validation.Valid; import java.util.List; import org.springframework.http.HttpStatus; import org.springframework.http.ResponseEntity; import org.springframework.web.bind.annotation.*; @RestController @RequestMapping("/v1/check-ins") public class CheckInController { private final CheckInService service; private final CheckInMapper mapper; private final CurrentUserProvider currentUserProvider; public CheckInController(CheckInService service, CheckInMapper mapper, CurrentUserProvider currentUserProvider) { this.service = service; this.mapper = mapper; this.currentUserProvider = currentUserProvider; } @PostMapping @Operation(summary = "Create CheckIn") public ResponseEntity<ApiResponse<CheckInResponse>> create(@Valid @RequestBody CheckInRequest request) { var created = service.create(currentUserProvider.getCurrentUser().userId(), request.mood(), request.reflection(), request.energyLevel(), request.recommendedPractice()); return ResponseEntity.status(HttpStatus.CREATED).body(ApiResponse.success(201, "Created", mapper.toResponse(created))); } @GetMapping @Operation(summary = "List check-ins") public ResponseEntity<ApiResponse<List<CheckInResponse>>> list() { return ResponseEntity.ok(ApiResponse.success(200, "Listed", service.list(currentUserProvider.getCurrentUser().userId()).stream().map(mapper::toResponse).toList())); } }
